import asyncio
from playwright.sync_api import sync_playwright

async def _snapshot_async():
    if '_page' not in globals():
        return '[DIRECT][EN]No active page. Use browser_navigate first.[/EN][PT]Sem página ativa. Use browser_navigate primeiro.[/PT]'
    elements = _page.evaluate('''() => {
        const selectors = [
            'button', 'a', 'input[type="submit"]', 'input[type="button"]',
            '[role="button"]', '[onclick]', '[tabindex]:not([tabindex="-1"])'
        ];
        const results = [];
        const seen = new Set();
        selectors.forEach(sel => {
            document.querySelectorAll(sel).forEach(el => {
                if (seen.has(el)) return;
                seen.add(el);
                const text = (el.innerText || el.value || el.getAttribute('aria-label') || el.getAttribute('title') || '').trim();
                if (text && text.length < 200) {
                    const tag = el.tagName.toLowerCase();
                    const id = el.id ? '#' + el.id : '';
                    const classes = el.className ? '.' + el.className.split(' ').join('.') : '';
                    results.push({
                        text: text,
                        selector: tag + id + classes,
                        tag: tag,
                        role: el.getAttribute('role') || null
                    });
                }
            });
        });
        return results.slice(0, 30);
    }''')
    if not elements:
        return '[DIRECT][EN]No clickable elements found.[/EN][PT]Nenhum elemento clicável encontrado.[/PT]'
    snapshot = '\n'.join([f"- \"{el['text']}\" -> {el['selector']}" for el in elements])
    return f'[DIRECT][EN]Page snapshot:\n{snapshot}[/EN][PT]Snapshot da página:\n{snapshot}[/PT]'

def _run_isolated():
    loop = asyncio.new_event_loop()
    asyncio.set_event_loop(loop)
    try:
        return loop.run_until_complete(_snapshot_async())
    finally:
        loop.close()

ai_response = _run_isolated()

import asyncio

async def _click_async():
    if '_page' not in globals():
        return '[DIRECT][EN]No active page.[/EN][PT]Sem página ativa.[/PT]'
    text = arguments.get('text')
    selector = arguments.get('selector')
    if text:
        _page.get_by_text(text, exact=True).click()
        return f'[DIRECT][EN]Clicked on element with text "{text}"[/EN][PT]Clicou no elemento com texto "{text}"[/PT]'
    elif selector:
        _page.click(selector)
        return f'[DIRECT][EN]Clicked on selector "{selector}"[/EN][PT]Clicou no seletor "{selector}"[/PT]'
    else:
        return '[DIRECT][EN]Provide either text or selector.[/EN][PT]Forneça texto ou seletor.[/PT]'

def _run_isolated():
    loop = asyncio.new_event_loop()
    asyncio.set_event_loop(loop)
    try:
        return loop.run_until_complete(_click_async())
    finally:
        loop.close()

ai_response = _run_isolated()

import asyncio

async def _type_async():
    if '_page' not in globals():
        return '[DIRECT][EN]No active page.[/EN][PT]Sem página ativa.[/PT]'
    label = arguments.get('label')
    selector = arguments.get('selector')
    text = arguments.get('text')
    if label:
        _page.get_by_label(label).fill(text)
    elif selector:
        _page.fill(selector, text)
    else:
        return '[DIRECT][EN]Provide label or selector.[/EN][PT]Forneça label ou seletor.[/PT]'
    if arguments.get('press_enter'):
        _page.keyboard.press('Enter')
    return f'[DIRECT][EN]Typed "{text}"[/EN][PT]Digitou "{text}"[/PT]'

def _run_isolated():
    loop = asyncio.new_event_loop()
    asyncio.set_event_loop(loop)
    try:
        return loop.run_until_complete(_type_async())
    finally:
        loop.close()

ai_response = _run_isolated()
